import './App.css';
import Modal  from './components/modal/Modal';
import { Button } from 'antd';
import { useState } from 'react';


function App() {

  const [showModal, setShowmodal] = useState(true);
  const closeModal = () => {
    setShowmodal(false)
  }

  const openModal = () => {
    setShowmodal(true)
  }

  return (
  <div className='App'>
    <Button onClick={openModal}>Open</Button>
    {showModal && <Modal>
      <h1>Nuriddin</h1>
        <p>Lorem ipsum, dolor sit amet consectetur adipisicing elit. Quos adipisci qui, ex odit ad accusantium voluptate cum consectetur veniam deleniti?</p>
        <Button onClick={closeModal}>Close</Button>
    </Modal> }

  </div>
  );
}

export default App;
